    @handle_errors("checking time conflict", default_return=False)
    def is_time_conflict(self, user_id, schedule_datetime):
        """
        Checks if there is a time conflict with any existing scheduled jobs for the user.

        NOTE:
        The `schedule` library commonly uses naive datetimes for `job.next_run`.
        Our schedule_datetime is often tz-aware (pytz). Subtracting naive/aware raises TypeError.
        """
        # Normalize schedule_datetime to naive for comparison against schedule's job.next_run.
        # We intentionally drop tzinfo here because schedule's next_run is not reliably tz-aware.
        if (
            isinstance(schedule_datetime, datetime)
            and schedule_datetime.tzinfo is not None
        ):
            schedule_dt_for_compare = schedule_datetime.replace(tzinfo=None)
        else:
            schedule_dt_for_compare = schedule_datetime

        for job in schedule.jobs:
            job_func = job.job_func
            if not job_func:
                continue

            job_args = getattr(job_func, "args", None)
            if job_args and job_args[0] == user_id:
                job_time = job.next_run
                if not job_time:
                    continue

                # Normalize job_time too (defensive)
                if isinstance(job_time, datetime) and job_time.tzinfo is not None:
                    job_time_for_compare = job_time.replace(tzinfo=None)
                else:
                    job_time_for_compare = job_time

                # Increase conflict window to 2 hours to prevent multiple messages at similar times
                try:
                    if (
                        abs(
                            (
                                job_time_for_compare - schedule_dt_for_compare
                            ).total_seconds()
                        )
                        < 7200
                    ):
                        return True
                except TypeError as e:
                    # Extremely defensive: if something weird slips through, log and treat as no conflict
                    logger.debug(
                        f"TypeError comparing job_time and schedule_datetime for conflict check: {e}"
                    )
                    continue

        return False

    @handle_errors("getting random time within period", default_return=None)
    def get_random_time_within_period(
        self, user_id, category, period, timezone_str="America/Regina"
    ):
        """Get a random time within a specified period for a given category."""
        tz = pytz.timezone(timezone_str)
        now_datetime = tz.localize(now_datetime_full())

        time_periods = get_schedule_time_periods(user_id, category)

        # Add validation for period existence
        if period not in time_periods:
            logger.error(
                f"Period '{period}' not found in time periods for user {user_id}, category {category}. Available periods: {list(time_periods.keys())}"
            )
            return None

        # Use canonical keys with fallback to legacy keys
        start_time = time_periods[period].get("start_time") or time_periods[period].get(
            "start"
        )
        end_time = time_periods[period].get("end_time") or time_periods[period].get(
            "end"
        )

        if not start_time or not end_time:
            logger.error(
                f"Missing start/end time for period {period} in user {user_id}, category {category}"
            )
            return None

        start_dt = parse_time_only_minute(start_time)
        end_dt = parse_time_only_minute(end_time)
        if start_dt is None or end_dt is None:
            logger.error(
                f"Invalid time format for period {period} in user {user_id}, category {category}: start='{start_time}', end='{end_time}'"
            )
            return None

        period_start_time = start_dt.time()
        period_end_time = end_dt.time()

        # Create timezone-aware datetime objects for today.
        # IMPORTANT: with pytz, never pass tzinfo=tz directly; always localize a naive datetime.
        start_datetime = tz.localize(
            datetime.combine(now_datetime.date(), period_start_time)
        )
        end_datetime = tz.localize(
            datetime.combine(now_datetime.date(), period_end_time)
        )

        # If the period has already ended today, schedule for tomorrow
        if end_datetime <= now_datetime or start_datetime <= now_datetime + timedelta(minutes=30):
            start_datetime += timedelta(days=1)
            end_datetime += timedelta(days=1)

        total_seconds = (end_datetime - start_datetime).total_seconds()
        if total_seconds <= 0:
            logger.error("Invalid time range calculated.")
            return None

        random_seconds = random.randint(0, int(total_seconds))
        random_datetime = start_datetime + timedelta(seconds=random_seconds)

        # Final safety check - ensure the time is in the future
        if random_datetime <= now_datetime:
            random_datetime += timedelta(days=1)

        random_time_str = format_timestamp(random_datetime, TIMESTAMP_MINUTE)
        logger.info(f"Scheduled random time: {random_time_str}")
        return random_time_str

    @handle_errors("logging scheduled tasks")
    def log_scheduled_tasks(self):
        """Logs all current and upcoming scheduled tasks in a user-friendly manner."""
        for job in schedule.jobs:
            job_func = job.job_func
            if not job_func:
                continue

            next_run = (
                format_timestamp(job.next_run, TIMESTAMP_FULL)
                if job.next_run
                else "None"
            )

            # Safely resolve function name for schedule-wrapped callables.
            # schedule often wraps functions in functools.partial, which may not have __name__.
            func_obj = job_func.func if hasattr(job_func, "func") else job_func
            task_name = getattr(func_obj, "__name__", "Scheduled Task")

            task_description = (
                str(job_func).split("function ")[-1].split(" at ")[0]
                if "function" in str(job_func)
                else task_name
            )

            category = "Generic Task"
            job_args = getattr(job_func, "args", None)
            if hasattr(job_func, "func") and job_args:
                category = job_args[0]

            logger.info(
                f"Task: {task_description}, Category: {category}, Scheduled at: {job.at_time}, Next run: {next_run}"
            )

    @handle_errors("handling sending scheduled message")
    def handle_sending_scheduled_message(
        self,
        user_id,
        category,
        retry_attempts=3,
        retry_delay=30,
        allow_deferral=True,
    ):
        """
        Handles the sending of scheduled messages with retries.
        This is a one-time job that removes itself after execution.
        """
        if self.communication_manager is None:
            logger.error("Communication manager is not initialized.")
            return

        attempt = 0
        while attempt < retry_attempts:
            try:
                # Try to send the message
                send_status = self.communication_manager.handle_message_sending(
                    user_id=user_id,
                    category=category,
                    is_scheduled_trigger=True,
                    allow_deferral=allow_deferral,
                )
                if send_status == "sent":
                    logger.info(
                        f"Message sent successfully for user {user_id}, category {category}."
                    )
                    # Remove this job after successful execution to make it a one-time job
                    self._remove_user_message_job(user_id, category)
                    return  # Exit after successful execution

                if send_status == "deferred":
                    logger.info(
                        f"Deferred scheduled message for user {user_id}, category {category}; scheduling one-time retry in 10 minutes."
                    )
                    self._remove_user_message_job(user_id, category)
                    self._schedule_deferred_message_retry(
                        user_id=user_id,
                        category=category,
                        delay_minutes=10,
                        retry_delay=retry_delay,
                    )
                    return

                if send_status == "skipped":
                    logger.info(
                        f"Skipping scheduled message for user {user_id}, category {category}: no eligible message content."
                    )
                    self._remove_user_message_job(user_id, category)
                    return
            except Exception as e:
                logger.error(
                    f"Error sending message for user {user_id}, category {category}: {e}"
                )
                attempt += 1
                logger.info(
                    f"Retrying in {retry_delay} seconds... ({attempt}/{retry_attempts})"
                )
                time.sleep(retry_delay)  # Wait before retrying

        # Remove job even if it failed after all retries
        self._remove_user_message_job(user_id, category)

    @handle_errors("scheduling deferred message retry", default_return=False)
    def _schedule_deferred_message_retry(
        self, user_id, category, delay_minutes=10, retry_delay=30
    ) -> bool:
        """Schedule a one-time retry for deferred scheduled sends."""
        retry_dt = now_datetime_full() + timedelta(minutes=delay_minutes)
        retry_time = format_timestamp(retry_dt, TIME_ONLY_MINUTE)
        schedule.every().day.at(retry_time).do(
            self.handle_sending_scheduled_message,
            user_id=user_id,
            category=category,
            retry_attempts=1,
            retry_delay=retry_delay,
            allow_deferral=False,
        )
        logger.info(
            f"Scheduled deferred retry for user {user_id}, category {category} at {retry_time} (allow_deferral=False)."
        )
        return True

    @handle_errors("removing user message job")
    def _remove_user_message_job(self, user_id, category):
        """
        Removes user message jobs from the scheduler after execution.
        This makes user message jobs effectively one-time jobs.
        """
        try:
            # Find and remove jobs for this user and category
            jobs_to_remove = []
            for job in schedule.jobs:
                job_func = job.job_func
                if not job_func:
                    continue
                job_args = getattr(job_func, "args", None)
                if (
                    hasattr(job_func, "func")
                    and job_func.func == self.handle_sending_scheduled_message
                    and job_args
                    and len(job_args) >= 2
                    and job_args[0] == user_id
                    and job_args[1] == category
                ):
                    jobs_to_remove.append(job)

            # Remove the jobs
            for job in jobs_to_remove:
                schedule.jobs.remove(job)
                logger.debug(
                    f"Removed one-time job for user {user_id}, category {category}"
                )

            if jobs_to_remove:
                logger.info(
                    f"Removed {len(jobs_to_remove)} completed message job(s) for user {user_id}, category {category}"
                )

        except Exception as e:
            logger.error(
                f"Error removing user message job for user {user_id}, category {category}: {e}"
            )

    @handle_errors("handling task reminder")
    def handle_task_reminder(self, user_id, task_id, retry_attempts=3, retry_delay=30):
        """
        Handles sending task reminders with retries.
        """
        if self.communication_manager is None:
            logger.error("Communication manager is not initialized.")
            return

        attempt = 0
        while attempt < retry_attempts:
            try:
                # Import task management functions
                from tasks import get_task_by_id, update_task

                # Get the task details
                task = get_task_by_id(user_id, task_id)
                if not task:
                    logger.error(f"Task {task_id} not found for user {user_id}")
                    return

                # Check if task is still active and not already completed
                if runtime_task_is_completed(task):
                    logger.info(
                        f"Task {task_id} is already completed, skipping reminder"
                    )
                    return

                # Send the task reminder via communication manager
                self.communication_manager.handle_task_reminder(user_id, task_id)

                # Mark reminder as sent
                update_task(user_id, task_id, {"reminder_sent": True})

                logger.info(
                    f"Task reminder sent successfully for user {user_id}, task {task_id}"
                )
                return  # Exit after successful execution

            except Exception as e:
                logger.error(
                    f"Error sending task reminder for user {user_id}, task {task_id}: {e}"
                )
                attempt += 1
                logger.info(
                    f"Retrying in {retry_delay} seconds... ({attempt}/{retry_attempts})"
                )
                time.sleep(retry_delay)  # Wait before retrying

    @handle_errors("setting wake timer")
    def set_wake_timer(
        self, schedule_time, user_id, category, period, wake_ahead_minutes=4
    ):
        """
        Set a Windows scheduled task to wake the computer before a scheduled message.

        Args:
            schedule_time: The datetime when the message is scheduled
            user_id: The user ID
            category: The message category
            period: The time period name
            wake_ahead_minutes: Minutes before schedule_time to wake the computer (default: 4)
        """
        # CRITICAL: Never create real Windows tasks for test users
        # Check if we're in test mode or if user data is in test directory
        if os.getenv("MHM_TESTING") == "1":
            logger.debug(
                f"Skipping wake timer creation for test user {user_id} (MHM_TESTING=1)"
            )
            return

        # Additional safety check: verify user data directory is not in tests directory
        try:
            from core.config import get_user_data_dir, BASE_DATA_DIR

            user_data_dir = get_user_data_dir(user_id)
            if user_data_dir and (
                "tests" in user_data_dir or "test" in BASE_DATA_DIR.lower()
            ):
                logger.debug(
                    f"Skipping wake timer creation for test user {user_id} (test data directory detected)"
                )
                return
        except Exception as e:
            logger.debug(f"Could not verify user data directory for {user_id}: {e}")
            # If we can't verify, err on the side of caution and skip task creation
            if os.getenv("MHM_TESTING") == "1":
                return

        # Adjust the schedule_time to wake the computer a few minutes earlier
        wake_time = schedule_time - timedelta(minutes=wake_ahead_minutes)
        # Task name must not contain : \ / * ? " < > | (Windows restriction; colon was causing 0x80070057)
        time_part_name = wake_time.strftime("%H%M")  # HHMM, no colon
        raw_name = f"Wake_{user_id}_{category}_{period}_{time_part_name}"
        invalid_chars = r'\/*?"<>|:' + "'"
        for char in invalid_chars:
            raw_name = raw_name.replace(char, "_")
        task_name = raw_name[:200] if len(raw_name) > 200 else raw_name  # Stay under path length limit

        task_time = format_timestamp(wake_time, TIME_ONLY_MINUTE)
        task_date = format_timestamp(wake_time, DATE_ONLY)
        # Build trigger time as ISO string; PowerShell will parse as [DateTime] for -At
        trigger_at_str = f"{task_date}T{task_time}:00"

        # PowerShell script to create the task with Wake computer enabled
        # -At expects [DateTime]; parse explicitly to avoid locale/format issues
        ps_command = f"""
        $action = New-ScheduledTaskAction -Execute 'cmd.exe' -Argument '/c exit'
        $at = [DateTime]::ParseExact('{trigger_at_str}', 'yyyy-MM-ddTHH:mm:ss', $null)
        $trigger = New-ScheduledTaskTrigger -Once -At $at
        $settings = New-ScheduledTaskSettingsSet -AllowStartIfOnBatteries -DontStopIfGoingOnBatteries -StartWhenAvailable -WakeToRun
        Register-ScheduledTask -TaskName '{task_name}' -Action $action -Trigger $trigger -Settings $settings -Force
        """

        # Execute the PowerShell command and capture the output
        result = subprocess.run(
            ["powershell", "-Command", ps_command], capture_output=True, text=True
        )

        if result.returncode == 0:
            logger.info(
                f"Wake timer set for {format_timestamp(wake_time, TIMESTAMP_MINUTE)} with task {task_name}"
            )
        else:
            logger.error(f"Failed to set wake timer with error: {result.stderr}")
            # Only log detailed info on errors
            logger.debug(f"PowerShell command: {ps_command.strip()}")
            logger.debug(f"PowerShell stdout: {result.stdout}")
            logger.debug(f"PowerShell return code: {result.returncode}")

    @handle_errors("cleaning up old tasks")
    def cleanup_old_tasks(self, user_id, category):
        """Cleans up all tasks (scheduled jobs and system tasks) associated with a given user and category."""
        # Count jobs before cleanup
        initial_job_count = len(schedule.jobs)
        jobs_removed = 0

        # Remove only jobs for this specific user and category
        jobs_to_remove = []
        for job in schedule.jobs:
            if self.is_job_for_category(job, user_id, category):
                jobs_to_remove.append(job)

        # Remove the identified jobs
        for job in jobs_to_remove:
            try:
                schedule.jobs.remove(job)
                jobs_removed += 1
                logger.debug(f"Removed job for user {user_id}, category {category}")
            except ValueError:
                # Job was already removed
                pass

        final_job_count = len(schedule.jobs)
        logger.info(
            f"In-memory scheduler cleanup completed for user {user_id}, category {category}. Removed {jobs_removed} jobs (from {initial_job_count} to {final_job_count} total jobs)."
        )

    @handle_errors("clearing all accumulated jobs")
    def clear_all_accumulated_jobs(self):
        """Clears all accumulated scheduler jobs and reschedules only the necessary ones."""
        logger.info("Clearing all accumulated scheduler jobs...")

        # Count jobs before cleanup
        initial_job_count = len(schedule.jobs)
        logger.info(
            f"Initial job count: {initial_job_count} (accumulated jobs to be cleared)"
        )

        # Clear all jobs
        schedule.clear()
        logger.info("All scheduler jobs cleared")

        # Don't reschedule daily jobs here - the main scheduler loop will handle that
        # This function is only for clearing accumulated jobs, not scheduling new ones

        final_job_count = len(schedule.jobs)
        jobs_cleared = initial_job_count - final_job_count

        # Log cleanup results in a single message
        if jobs_cleared > 0:
            logger.info(
                f"Job cleanup complete: {jobs_cleared} accumulated jobs cleared"
            )
        elif jobs_cleared == 0:
            logger.debug(
                "Job cleanup complete: No accumulated jobs to clear (system was already clean)"
            )
        else:
            logger.info(
                f"Job cleanup complete: Added {abs(jobs_cleared)} scheduler jobs (system had fewer jobs than expected)"
            )

        # Cleanup system tasks for all users/categories
        logger.info("Starting system task cleanup for all users...")

        try:
            result = subprocess.run(
                ["schtasks", "/query", "/fo", "LIST", "/v"],
                capture_output=True,
                text=True,
            )
            if result.returncode != 0:
                logger.debug(f"Could not query system tasks: {result.stderr}")
                logger.info("System task cleanup completed (no tasks to clean).")
                return

            tasks = result.stdout.splitlines()
            tasks_deleted = 0

            # Get user IDs for task cleanup
            user_ids = get_all_user_ids()

            # Look for tasks with our user ID prefixes
            for line in tasks:
                if line.startswith("TaskName:"):
                    task_name = line.split(":")[1].strip()
                    # Check if this is one of our MHM wake tasks
                    if "Wake_" in task_name and any(
                        user_id in task_name for user_id in user_ids
                    ):
                        logger.info(f"Deleting old system task: {task_name}")
                        try:
                            # Use check=False to prevent exceptions on missing tasks
                            del_result = subprocess.run(
                                ["schtasks", "/delete", "/tn", task_name, "/f"],
                                capture_output=True,
                                text=True,
                                check=False,
                            )
                            if del_result.returncode == 0:
                                tasks_deleted += 1
                                logger.debug(f"Successfully deleted task: {task_name}")
                            else:
                                # Task probably doesn't exist anymore - this is fine
                                logger.debug(
                                    f"Task {task_name} may already be deleted: {del_result.stderr}"
                                )
                        except Exception as del_error:
                            logger.debug(
                                f"Error deleting task {task_name}: {del_error}"
                            )

            logger.info(
                f"System task cleanup completed: {tasks_deleted} tasks deleted."
            )
            if tasks_deleted > 0:
                logger.debug(f"Deleted {tasks_deleted} old system tasks")

        except Exception as query_error:
            logger.debug(f"Error querying system tasks for cleanup: {query_error}")
            logger.info("System task cleanup skipped (query failed).")

    @handle_errors("scheduling all task reminders")
    def schedule_all_task_reminders(self, user_id):
        """
        Schedule reminders for all active tasks for a user.
        For each reminder period, pick one random task and schedule it at a random time within the period.
        """
        try:
            from tasks import load_active_tasks, are_tasks_enabled
            from core.schedule_management import get_schedule_time_periods

            # Check if tasks are enabled for this user
            if not are_tasks_enabled(user_id):
                logger.debug(f"Tasks not enabled for user {user_id}")
                return

            # Get user's configured task reminder periods from the periods structure
            task_periods = get_schedule_time_periods(user_id, "tasks")
            if not task_periods:
                logger.debug(f"No task reminder periods configured for user {user_id}")
                return

            # Load active tasks
            active_tasks = load_active_tasks(user_id)

            from tasks.task_data_handlers import runtime_task_is_completed

            # Filter to only incomplete tasks
            incomplete_tasks = [
                task for task in active_tasks if not runtime_task_is_completed(task)
            ]

            if not incomplete_tasks:
                logger.debug(f"No incomplete tasks found for user {user_id}")
                return

            scheduled_count = 0

            # For each active task reminder period, pick one random task and schedule it
            for period_name, period_data in task_periods.items():
                if not period_data.get("active", True):
                    continue

                # Pick one random task for this period
                selected_task = self.select_task_for_reminder(incomplete_tasks)

                if not selected_task:
                    logger.debug(
                        f"No task selected for period {period_name} for user {user_id}"
                    )
                    continue

                start_time = period_data.get("start_time")
                end_time = period_data.get("end_time")

                if not start_time or not end_time:
                    logger.warning(
                        f"Missing start/end time for task reminder period '{period_name}' in user {user_id}"
                    )
                    continue

                # Generate a random time within the period
                random_time = self.get_random_time_within_task_period(
                    start_time, end_time
                )
                if not random_time:
                    logger.warning(
                        f"Could not generate random time for period {start_time}-{end_time}"
                    )
                    continue

                # Schedule the task reminder using canonical task id.
                selected_task_id = str(selected_task.get("id") or "").strip()
                if not selected_task_id:
                    logger.warning(
                        f"Skipping task reminder for user {user_id}: selected task missing canonical id"
                    )
                    continue

                if self.schedule_task_reminder_at_time(
                    user_id, selected_task_id, random_time
                ):
                    scheduled_count += 1
                    logger.info(
                        f"Scheduled reminder for task '{selected_task['title']}' at {random_time} (period: {period_name} {start_time}-{end_time})"
                    )

            logger.info(
                f"Scheduled {scheduled_count} task reminders for user {user_id}"
            )

        except Exception as e:
            logger.error(f"Error scheduling task reminders for user {user_id}: {e}")

    @handle_errors("selecting task for reminder with priority and due date weighting")
    def _select_task_for_reminder__handle_edge_cases(self, incomplete_tasks):
        """Handle edge cases for task selection."""
        if not incomplete_tasks:
            return None

        # If only one task, return it
        if len(incomplete_tasks) == 1:
            return incomplete_tasks[0]

        return "PROCEED"  # Signal to continue with normal processing

    @handle_errors("calculating priority weight for task reminder")
    def _select_task_for_reminder__calculate_priority_weight(self, task):
        """Calculate priority-based weight for a task."""
        priority = task.get("priority", "medium").lower()
        priority_multipliers = {
            "critical": 3.0,  # Critical priority tasks 3x more likely
            "high": 2.0,  # High priority tasks 2x more likely
            "medium": 1.5,  # Medium priority tasks 1.5x more likely
            "low": 1.0,  # Low priority tasks base weight
            "none": 0.8,  # No priority tasks slightly less likely
        }
        return priority_multipliers.get(priority, 1.0)

    @handle_errors(
        "calculating due date weight for reminder selection",
        default_return=1.0,
        user_friendly=False,
    )
    def _select_task_for_reminder__calculate_due_date_weight(self, task, today):
        """Calculate due date proximity weight for a task."""
        from tasks.task_data_handlers import runtime_task_due_date

        due_date_str = runtime_task_due_date(task)
        if not due_date_str:
            # No due date: slight reduction to encourage setting due dates
            return 0.9

        due_date_dt = parse_date_only(due_date_str)
        if due_date_dt is None:
            # Invalid date format, use base weight
            return 1.0

        due_date = due_date_dt.date()
        days_until_due = (due_date - today).days

        # Sliding scale calculation
        if days_until_due < 0:
            # Overdue tasks: exponential increase based on how overdue
            # Formula: 2.5 + (days_overdue * 0.1), max 4.0
            days_overdue = abs(days_until_due)
            return min(2.5 + (days_overdue * 0.1), 4.0)
        elif days_until_due == 0:
            # Due today: maximum weight
            return 2.5
        elif days_until_due <= 7:
            # Due within a week: sliding scale from 2.5 to 1.0
            # Formula: 2.5 - (days_until_due * 0.2)
            return max(2.5 - (days_until_due * 0.2), 1.0)
        elif days_until_due <= 30:
            # Due within a month: sliding scale from 1.0 to 0.8
            # Formula: 1.0 - (days_until_due - 7) * 0.01
            return max(1.0 - (days_until_due - 7) * 0.01, 0.8)
        else:
            # Due later than a month: base weight
            return 0.8

    @handle_errors("calculating task weights for reminder selection")
    def _select_task_for_reminder__calculate_task_weights(
        self, incomplete_tasks, today
    ):
        """Calculate weights for all tasks."""
        task_weights = []

        for task in incomplete_tasks:
            weight = 1.0  # Base weight

            # Apply priority weighting
            priority_multiplier = (
                self._select_task_for_reminder__calculate_priority_weight(task)
            )
            weight *= priority_multiplier

            # Apply due date proximity weighting
            due_date_multiplier = (
                self._select_task_for_reminder__calculate_due_date_weight(task, today)
            )
            weight *= due_date_multiplier

            task_weights.append((task, weight))

        return task_weights

    @handle_errors("building task key for reminder selection", default_return="")
    def _select_task_for_reminder__task_key(
        self, task: dict[str, Any], index: int
    ) -> str:
        """Build a stable key for tracking reminder selection state."""
        candidate_keys = [
            str(task.get("id") or "").strip(),
            str(task.get("short_id") or "").strip(),
            str(task.get("uuid") or "").strip(),
            str(task.get("title") or "").strip(),
        ]
        # Fall back to index when no identifier data is present
        base_key = next((key for key in candidate_keys if key), f"idx-{index}")
        return f"{base_key}|{index}"

    @handle_errors("selecting task by weight for reminder", default_return=None)
    def _select_task_for_reminder__select_task_by_weight(
        self, task_weights, incomplete_tasks
    ):
        """Select a task based on calculated weights using weighted random selection."""
        import random

        if not task_weights:
            return random.choice(incomplete_tasks) if incomplete_tasks else None

        total_weight = sum(weight for _, weight in task_weights)
        if total_weight <= 0:
            # Fallback to random selection if all weights are zero or invalid
            return random.choice(incomplete_tasks)

        # Use weighted random selection for proper semi-random behavior
        # This ensures higher-weighted tasks are more likely but not always selected
        rand_value = random.uniform(0, total_weight)
        cumulative_weight = 0.0

        # Clean up stale state first
        active_keys = {
            self._select_task_for_reminder__task_key(t, i)
            for i, (t, _) in enumerate(task_weights)
        }
        for key in list(self._reminder_selection_state.keys()):
            if key not in active_keys:
                self._reminder_selection_state.pop(key, None)

        for index, (task, weight) in enumerate(task_weights):
            cumulative_weight += weight
            if rand_value <= cumulative_weight:
                # Update accumulated state for smooth distribution over time
                task_key = self._select_task_for_reminder__task_key(task, index)
                previous_score = self._reminder_selection_state.get(task_key, 0.0)
                self._reminder_selection_state[task_key] = previous_score + weight

                return task

        # Fallback to last task if something went wrong
        return task_weights[-1][0] if task_weights else random.choice(incomplete_tasks)

    @handle_errors("selecting task for reminder", default_return=None)
    def select_task_for_reminder(
        self, incomplete_tasks: list[dict[str, Any]]
    ) -> dict[str, Any]:
        """
        Select a task for reminder using priority-based and due date proximity weighting.

        Args:
            incomplete_tasks: List of incomplete tasks to choose from

        Returns:
            Selected task dictionary
        """
        # Handle edge cases
        edge_case_result = self._select_task_for_reminder__handle_edge_cases(
            incomplete_tasks
        )
        if edge_case_result != "PROCEED":
            return edge_case_result

        # Calculate weights for each task
        today = now_datetime_full().date()
        task_weights = self._select_task_for_reminder__calculate_task_weights(
            incomplete_tasks, today
        )

        # Select task based on weights
        selected_task = self._select_task_for_reminder__select_task_by_weight(
            task_weights, incomplete_tasks
        )

        from tasks.task_data_handlers import runtime_task_due_date

        logger.debug(
            f"Selected task '{selected_task.get('title', 'Unknown')}' with priority '{selected_task.get('priority', 'medium')}' and due date '{runtime_task_due_date(selected_task) or 'None'}'"
        )

        return selected_task

    @handle_errors("getting random time within task period")
    def get_random_time_within_task_period(self, start_time, end_time):
        """
        Generate a random time within a task reminder period.
        Args:
            start_time: Start time in HH:MM format (e.g., "17:00")
            end_time: End time in HH:MM format (e.g., "18:00")
        Returns:
            Random time in HH:MM format
        """
        try:
            from datetime import timedelta
            import random

            # Parse start and end times (HH:MM)
            start_dt = parse_time_only_minute(start_time)
            end_dt = parse_time_only_minute(end_time)
            if start_dt is None or end_dt is None:
                logger.error(f"Invalid time range: {start_time} to {end_time}")
                return None

            # If end time is before start time, it means the period spans midnight
            # For now, we'll assume it's the same day
            if end_dt < start_dt:
                end_dt += timedelta(days=1)

            # Calculate total seconds in the period
            total_seconds = (end_dt - start_dt).total_seconds()

            if total_seconds <= 0:
                logger.error(f"Invalid time range: {start_time} to {end_time}")
                return None

            # Generate random seconds within the period
            random_seconds = random.randint(0, int(total_seconds))
            random_dt = start_dt + timedelta(seconds=random_seconds)

            # Format as HH:MM
            random_time = format_timestamp(random_dt, TIME_ONLY_MINUTE)

            logger.debug(
                f"Generated random time {random_time} within period {start_time}-{end_time}"
            )
            return random_time

        except Exception as e:
            logger.error(
                f"Error generating random time within period {start_time}-{end_time}: {e}"
            )
            return None

    @handle_errors("scheduling task reminder at specific time")
    def schedule_task_reminder_at_time(self, user_id, task_id, reminder_time):
        """
        Schedule a reminder for a specific task at the specified time (daily).
        """
        try:
            from tasks import get_task_by_id

            # Get the task to verify it exists and is active
            task = get_task_by_id(user_id, task_id)
            if not task:
                logger.error(f"Task {task_id} not found for user {user_id}")
                return False

            if runtime_task_is_completed(task):
                logger.info(
                    f"Task {task_id} is already completed, skipping reminder scheduling"
                )
                return False

            # Parse the reminder time
            try:
                hour, minute = map(int, reminder_time.split(":"))
                time_str = f"{hour:02d}:{minute:02d}"
            except ValueError:
                logger.error(f"Invalid reminder time format: {reminder_time}")
                return False

            # Schedule the task reminder
            schedule.every().day.at(time_str).do(
                self.handle_task_reminder, user_id=user_id, task_id=task_id
            )

            # Set wake timer for the task reminder
            from datetime import datetime, timedelta
            import pytz

            # Create datetime for today at the specified time
            tz = pytz.timezone("America/Regina")
            now = tz.localize(now_datetime_full())
            today = now.date()

            # Parse the reminder time
            hour, minute = map(int, time_str.split(":"))
            # Build a timezone-aware datetime for today's reminder time.
            # IMPORTANT: with pytz, never pass tzinfo=tz directly; always localize a naive datetime.
            schedule_time_obj = datetime.min.time().replace(hour=hour, minute=minute)
            schedule_datetime = tz.localize(datetime.combine(today, schedule_time_obj))

            # If the time has already passed today, schedule for tomorrow
            if schedule_datetime <= now:
                schedule_datetime += timedelta(days=1)

            # Set wake timer for task reminder
            self.set_wake_timer(schedule_datetime, user_id, "tasks", "task_reminder")

            logger.info(
                f"Scheduled daily task reminder for user {user_id}, task {task_id} at {time_str}"
            )
            return True

        except Exception as e:
            logger.error(
                f"Error scheduling task reminder for user {user_id}, task {task_id}: {e}"
            )
            return False

    @handle_errors("scheduling task reminder at specific datetime")
    def schedule_task_reminder_at_datetime(self, user_id, task_id, date_str, time_str):
        """
        Schedule a reminder for a specific task at a specific date and time.
        """
        try:
            from tasks import get_task_by_id

            # Get the task to verify it exists and is active
            task = get_task_by_id(user_id, task_id)
            if not task:
                logger.error(f"Task {task_id} not found for user {user_id}")
                return False

            if runtime_task_is_completed(task):
                logger.info(
                    f"Task {task_id} is already completed, skipping reminder scheduling"
                )
                return False

            # Parse the date and time (expects canonical TIMESTAMP_MINUTE)
            reminder_datetime = parse_timestamp_minute(f"{date_str} {time_str}")
            if reminder_datetime is None:
                logger.error(f"Invalid date/time format: {date_str} {time_str}")
                return False

            # Check if the reminder time is in the past
            if reminder_datetime < now_datetime_full():
                logger.debug(
                    f"Reminder time {reminder_datetime} is in the past, skipping"
                )
                return False

            # Calculate delay until the reminder time
            delay_seconds = (reminder_datetime - now_datetime_full()).total_seconds()

            # Schedule the task reminder
            delay_seconds_int = max(1, int(delay_seconds))
            schedule.every(delay_seconds_int).seconds.do(
                self.handle_task_reminder, user_id=user_id, task_id=task_id
            )

            logger.info(
                f"Scheduled one-time task reminder for user {user_id}, task {task_id} at {reminder_datetime}"
            )
            return True

        except Exception as e:
            logger.error(
                f"Error scheduling task reminder for user {user_id}, task {task_id}: {e}"
            )
            return False

    @handle_errors("cleaning up task reminders")
    def cleanup_task_reminders(self, user_id, task_id):
        """
        Clean up all reminders for a specific task.

        Finds and removes all APScheduler jobs that call handle_task_reminder for the given task_id.
        Handles both one-time reminders (schedule_task_reminder_at_datetime) and daily reminders (schedule_task_reminder_at_time).

        Args:
            user_id: The user's ID
            task_id: The task ID to clean up reminders for

        Returns:
            bool: True if cleanup succeeded (or no reminders found), False on error
        """
        try:
            if not user_id or not task_id:
                logger.error(
                    f"Invalid parameters for cleanup_task_reminders: user_id={user_id}, task_id={task_id}"
                )
                return False

            # Count jobs before cleanup
            initial_job_count = len(schedule.jobs)
            jobs_to_remove = []

            # Find all jobs that call handle_task_reminder with this user_id and task_id
            for job in schedule.jobs:
                try:
                    # Check if this is a task reminder job
                    # Jobs created by schedule_task_reminder_at_datetime use: schedule.every(delay).seconds.do(handle_task_reminder, user_id=..., task_id=...)
                    # Jobs created by schedule_task_reminder_at_time use: schedule.every().day.at(time).do(handle_task_reminder, user_id=..., task_id=...)

                    # Check if job function is handle_task_reminder
                    job_func = job.job_func
                    if not job_func:
                        continue
                    if (
                        hasattr(job_func, "func")
                        and job_func.func == self.handle_task_reminder
                    ):
                        # Check keyword arguments for user_id and task_id
                        if hasattr(job_func, "keywords"):
                            kwargs = job_func.keywords
                            if (
                                kwargs.get("user_id") == user_id
                                and kwargs.get("task_id") == task_id
                            ):
                                jobs_to_remove.append(job)
                                logger.debug(
                                    f"Found reminder job for task {task_id}, user {user_id}"
                                )

                    # Also check positional arguments (some job types may use args instead of keywords)
                    else:
                        args = getattr(job_func, "args", None)
                        if args and len(args) >= 2:
                            # handle_task_reminder signature: (self, user_id, task_id, ...)
                            if (
                                len(args) >= 2
                                and args[0] == user_id
                                and args[1] == task_id
                            ):
                                # Verify it's actually handle_task_reminder
                                if (
                                    hasattr(job_func, "func")
                                    and job_func.func == self.handle_task_reminder
                                ):
                                    jobs_to_remove.append(job)
                                    logger.debug(
                                        f"Found reminder job for task {task_id}, user {user_id} (positional args)"
                                    )

                except Exception as e:
                    # Skip jobs that can't be inspected
                    logger.debug(f"Could not inspect job for cleanup: {e}")
                    continue

            # Remove the identified jobs
            jobs_removed = 0
            for job in jobs_to_remove:
                try:
                    schedule.jobs.remove(job)
                    jobs_removed += 1
                    logger.debug(
                        f"Removed reminder job for task {task_id}, user {user_id}"
                    )
                except ValueError:
                    # Job was already removed
                    pass

            final_job_count = len(schedule.jobs)
            logger.info(
                f"Cleaned up {jobs_removed} reminder job(s) for task {task_id}, user {user_id} "
                f"(from {initial_job_count} to {final_job_count} total jobs)"
            )

            return True

        except Exception as e:
            logger.error(
                f"Error cleaning up task reminders for task {task_id}, user {user_id}: {e}"
            )
            return False

    @handle_errors("cleaning up orphaned task reminders")
    def cleanup_orphaned_task_reminders(self):
        """
        Periodic cleanup job to remove reminders for tasks that no longer exist.

        Scans all scheduled reminder jobs and verifies the associated tasks still exist.
        Removes reminders for tasks that have been deleted or completed.
        Runs daily at 03:00.
        """
        try:
            logger.info("Starting periodic cleanup of orphaned task reminders")

            # Get all active users (we'll need to scan their tasks)
            from core import get_all_user_ids

            get_all_user_ids()

            orphaned_count = 0
            total_checked = 0

            # Find all task reminder jobs
            jobs_to_check = []
            for job in schedule.jobs:
                try:
                    # Check if this is a task reminder job
                    job_func = job.job_func
                    if not job_func:
                        continue
                    if (
                        hasattr(job_func, "func")
                        and job_func.func == self.handle_task_reminder
                    ) and hasattr(job_func, "keywords"):
                        kwargs = job_func.keywords
                        user_id = kwargs.get("user_id")
                        task_id = kwargs.get("task_id")
                        if user_id and task_id:
                            jobs_to_check.append((job, user_id, task_id))
                            total_checked += 1
                except Exception as e:
                    logger.debug(f"Could not inspect job for orphaned cleanup: {e}")
                    continue

            # Check each job's task still exists
            from tasks import get_task_by_id

            for job, user_id, task_id in jobs_to_check:
                try:
                    task = get_task_by_id(user_id, task_id)
                    if not task:
                        # Task doesn't exist - remove the reminder job
                        try:
                            schedule.jobs.remove(job)
                            orphaned_count += 1
                            logger.info(
                                f"Removed orphaned reminder for non-existent task {task_id}, user {user_id}"
                            )
                        except ValueError:
                            # Job was already removed
                            pass
                    elif runtime_task_is_completed(task):
                        # Task is completed - remove the reminder job
                        try:
                            schedule.jobs.remove(job)
                            orphaned_count += 1
                            logger.info(
                                f"Removed reminder for completed task {task_id}, user {user_id}"
                            )
                        except ValueError:
                            # Job was already removed
                            pass
                except Exception as e:
                    logger.debug(
                        f"Error checking task {task_id} for user {user_id}: {e}"
                    )
                    continue

            logger.info(
                f"Orphaned reminder cleanup complete: checked {total_checked} reminders, removed {orphaned_count} orphaned reminders"
            )

        except Exception as e:
            logger.error(
                f"Error during orphaned task reminder cleanup: {e}", exc_info=True
            )

    @handle_errors("performing daily log archival")
    def perform_daily_log_archival(self):
