    def _aggregate_doc_sync_results(self, all_results: dict[str, Any]) -> dict[str, Any]:
        """Aggregate results from all documentation sync tools into unified summary."""
        summary: dict[str, Any] = {
            'status': 'PASS',
            'total_issues': 0,
            'paired_doc_issues': 0,
            'path_drift_issues': 0,
            'ascii_issues': 0,
            'heading_numbering_issues': 0,
            'missing_address_issues': 0,
            'unconverted_link_issues': 0,
            'path_drift_files': [],
            'example_marker_hint_count': 0,
        }
        # Aggregate paired docs
        paired_docs = all_results.get('paired_docs', {})
        if isinstance(paired_docs, dict):
            for _issue_type, issues in paired_docs.items():
                if isinstance(issues, list):
                    summary['paired_doc_issues'] += len(issues)
                    summary['total_issues'] += len(issues)
        # Aggregate path drift
        path_drift = all_results.get('path_drift', {})
        if isinstance(path_drift, dict):
            summary['path_drift_issues'] = path_drift.get('summary', {}).get('total_issues', 0)
            summary['total_issues'] += summary['path_drift_issues']
            files = path_drift.get('files', {})
            if isinstance(files, dict):
                summary['path_drift_files'] = list(files.keys())[:10]
        # Aggregate ASCII compliance
        ascii_compliance = all_results.get('ascii_compliance', {})
        if isinstance(ascii_compliance, dict):
            summary['ascii_issues'] = ascii_compliance.get('summary', {}).get('total_issues', 0)
            summary['total_issues'] += summary['ascii_issues']
        # Aggregate heading numbering
        heading_numbering = all_results.get('heading_numbering', {})
        if isinstance(heading_numbering, dict):
            summary['heading_numbering_issues'] = heading_numbering.get('summary', {}).get('total_issues', 0)
            summary['total_issues'] += summary['heading_numbering_issues']
        # Aggregate missing addresses
        missing_addresses = all_results.get('missing_addresses', {})
        if isinstance(missing_addresses, dict):
            summary['missing_address_issues'] = missing_addresses.get('summary', {}).get('total_issues', 0)
            summary['total_issues'] += summary['missing_address_issues']
        # Aggregate unconverted links
        unconverted_links = all_results.get('unconverted_links', {})
        if isinstance(unconverted_links, dict):
            summary['unconverted_link_issues'] = unconverted_links.get('summary', {}).get('total_issues', 0)
            summary['total_issues'] += summary['unconverted_link_issues']
        # Example markers (advisory): do not affect total_issues or PASS/FAIL
        example_findings = all_results.get('example_marker_findings', {})
        if isinstance(example_findings, dict):
            summary['example_marker_hint_count'] = sum(
                len(v) for v in example_findings.values() if isinstance(v, list)
            )
        # Determine overall status
        if summary['total_issues'] > 0:
            summary['status'] = 'FAIL'
        else:
            summary['status'] = 'PASS'
        return summary

    def _parse_legacy_output(self, output: str) -> dict[str, Any]:
        """Extract headline metrics from the legacy cleanup output."""
        summary: dict[str, Any] = {
            'files_with_issues': None,
            'legacy_markers': None,
            'report_path': None
        }
        if not isinstance(output, str) or not output.strip():
            return summary
        for raw_line in output.splitlines():
            line = raw_line.strip()
            if not line:
                continue
            if line.startswith('Files with issues:'):
                value = self._extract_first_int(line)
                if value is not None:
                    summary['files_with_issues'] = value
                continue
            if line.startswith('legacy_compatibility_markers:'):
                value = self._extract_first_int(line)
                if value is not None:
                    summary['legacy_markers'] = value
                continue
            if 'report saved to:' in line.lower():
                parts = line.split(':', 1)
                if len(parts) == 2:
                    summary['report_path'] = parts[1].strip()
        return summary

    def _load_mtime_cached_tool_results(
        self, 
        tool_name: str, 
        domain: str, 
        result: dict,
        parse_output_func: Callable[[str], dict[str, Any]] | None = None,
        cache_converter_func: Callable[[dict[str, Any]], dict[str, Any]] | None = None
    ) -> dict[str, Any]:
        """
        Unified helper for loading results from mtime-cached tools.

        After tool execution, this method:
        1. Loads from cache FIRST (fresh data after tool execution)
        2. Converts cache format to results format (using converter or default)
        3. Saves to results JSON
        4. Returns results dict
        5. Falls back to parsing output if cache fails
        """
        from ..output_storage import save_tool_result, load_tool_cache

        # Step 1: Load from cache FIRST using standardized storage
        cache_data = None
        try:
            cache_data = load_tool_cache(tool_name, domain, project_root=self.project_root)
            if cache_data:
                logger.debug(f"Loaded {tool_name} from cache (fresh data after execution)")
        except Exception as cache_error:
            logger.debug(f"Failed to load {tool_name} from cache: {cache_error}")

        # Step 2: Convert cache format to results format (standard format)
        if cache_data and isinstance(cache_data, dict):
            # Handle both formats: wrapped {'data': {...}} and direct {file_path: {...}}
            if 'data' in cache_data:
                file_data = cache_data.get('data', {})
            else:
                # Direct format - cache_data IS the file data
                file_data = cache_data
            if file_data and isinstance(file_data, dict):
                # CRITICAL: Filter out entries for files that no longer exist
                # The cache may contain entries for deleted files, which would cause stale data
                filtered_file_data = {}
                for file_path_str, file_info in file_data.items():
                    if isinstance(file_info, dict):
                        # Check if file still exists
                        try:
                            file_path = self.project_root / file_path_str
                            if file_path.exists():
                                # Verify mtime matches (file hasn't been modified)
                                cached_mtime = file_info.get('mtime')
                                if cached_mtime is not None:
                                    current_mtime = file_path.stat().st_mtime
                                    if current_mtime == cached_mtime:
                                        filtered_file_data[file_path_str] = file_info
                                    else:
                                        logger.debug(f"Skipping {file_path_str} - mtime mismatch (file modified)")
                                else:
                                    # No mtime in cache, include it but it will be re-scanned
                                    filtered_file_data[file_path_str] = file_info
                            else:
                                logger.debug(f"Skipping {file_path_str} - file no longer exists")
                        except (OSError, ValueError) as e:
                            logger.debug(f"Skipping {file_path_str} - error checking file: {e}")
                    else:
                        # Invalid format, skip
                        logger.debug(f"Skipping {file_path_str} - invalid cache entry format")

                # Use filtered data
                file_data = filtered_file_data
                # Use custom converter if provided, otherwise use default
                if cache_converter_func:
                    raw_result = cache_converter_func(file_data)
                else:
                    # Default converter (raw, pre-standard)
                    files_with_issues = {}
                    total_issues = 0
                    for file_path, file_info in file_data.items():
                        if isinstance(file_info, dict):
                            results = file_info.get('results', [])
                            if results:
                                files_with_issues[file_path] = len(results)
                                total_issues += len(results)
                    raw_result = {
                        'files': files_with_issues,
                        'file_count': len(files_with_issues),
                        'total_issues': total_issues
                    }

                # Ensure standard format with summary/details
                tool_result = raw_result
                if not (isinstance(raw_result, dict) and isinstance(raw_result.get('summary'), dict)):
                    files_with_issues = raw_result.get('files', {}) if isinstance(raw_result, dict) else {}
                    file_count = raw_result.get('file_count')
                    if not isinstance(file_count, int):
                        file_count = len(files_with_issues) if isinstance(files_with_issues, dict) else 0
                    total_issues = raw_result.get('total_issues', 0) if isinstance(raw_result, dict) else 0
                    tool_result = self._create_standard_format_result(
                        total_issues,
                        file_count,
                        files_with_issues if isinstance(files_with_issues, dict) else {},
                        raw_result if isinstance(raw_result, dict) else {}
                    )

                # Step 3: Save to results JSON and populate in-memory cache
                try:
                    save_tool_result(tool_name, domain, tool_result, project_root=self.project_root)
                    logger.debug(f"Regenerated {tool_name}_results.json from fresh cache")
                    # Populate in-memory cache for current audit run
                    if not hasattr(self, 'results_cache'):
                        self.results_cache = {}
                    self.results_cache[tool_name] = tool_result
                except Exception as save_error:
                    logger.debug(f"Failed to save {tool_name} results: {save_error}")

                return tool_result

        # Step 4: Fallback to parsing output if cache failed
        if result.get('output') or result.get('success'):
            if parse_output_func:
                tool_result = parse_output_func(result.get('output', ''))
                if isinstance(tool_result, dict) and 'summary' not in tool_result:
                    files_with_issues = tool_result.get('files', {})
                    file_count = tool_result.get('file_count', len(files_with_issues) if isinstance(files_with_issues, dict) else 0)
                    total_issues = tool_result.get('total_issues', 0)
                    tool_result = self._create_standard_format_result(
                        total_issues,
                        file_count,
                        files_with_issues if isinstance(files_with_issues, dict) else {},
                        tool_result
                    )
                try:
                    save_tool_result(tool_name, domain, tool_result, project_root=self.project_root)
                    logger.debug(f"Saved {tool_name} results from parsed output")
                    # Populate in-memory cache for current audit run
                    if not hasattr(self, 'results_cache'):
                        self.results_cache = {}
                    self.results_cache[tool_name] = tool_result
                except Exception as save_error:
                    logger.debug(f"Failed to save {tool_name} results: {save_error}")
                return tool_result
            else:
                logger.warning(f"No parser function provided for {tool_name}, cannot parse output")
        else:
            logger.warning(f"{tool_name} failed: {result.get('error', 'Unknown error')}")

        # Return empty result if all else fails
        return {
            'files': {},
            'file_count': 0,
            'total_issues': 0
        }

"""
Base class for AI functionality tests

Provides shared utilities for all AI test modules.
"""

import os

from unittest.mock import patch

from ai.chatbot import AIChatBotSingleton
from tests.test_helpers.test_utilities import TestUserFactory
from core import get_user_id_by_identifier
from tests.ai.ai_response_validator import AIResponseValidator
from core.time_utilities import DATE_ONLY, format_timestamp, now_datetime_full


class AITestBase:
    """Base class for AI functionality tests with shared utilities"""

    def __init__(self, test_data_dir, results_collector):
        """
        Initialize test base

        Args:
            test_data_dir: Directory for test data
            results_collector: Object that collects test results (must have results list)
        """
        self.test_data_dir = test_data_dir
        self.results_collector = results_collector
        self.chatbot = AIChatBotSingleton()
        self._test_users = {}  # Cache created test users

    def log_test(
        self,
        test_id,
        test_name,
        status,
        notes="",
        issues="",
        prompt="",
        response="",
        response_time=None,
        metrics=None,
        test_type="",
        context_info=None,
    ):
        """
        Log test result with optional performance metrics and automatic response review.

        Args:
            test_id: Test identifier (e.g., "T-1.1")
            test_name: Human-readable test name
            status: Initial status ("PASS", "PARTIAL", "FAIL")
            notes: Optional notes
            issues: Optional issues string
            prompt: Original prompt (for validation)
            response: AI response (for validation)
            response_time: Optional response time in seconds
            metrics: Optional metrics dict
            test_type: Type of test (e.g., "command", "chat", "contextual") - used for validation
            context_info: Optional dict with context information (check-ins, tasks, etc.) available to AI
        """
        # Automatically review response if provided
        reviewed_status = status
        review_issues = []
        review_warnings = []

        if response and isinstance(response, str) and test_type != "mode_detection":
            # Skip validation for mode detection tests (they return "Mode: X" which is expected)
            reviewed_status, review_issues, review_warnings = (
                AIResponseValidator.review_response(
                    response, prompt, test_name, test_type, context_info
                )
            )

            # Combine existing issues with review issues
            all_issues = []
            if issues:
                all_issues.append(issues)
            if review_issues:
                all_issues.extend(review_issues)

            # Combine issues into a single string for display
            if all_issues:
                issues = " | ".join(all_issues)

            # Update status based on review (review can only make status worse, not better)
            if reviewed_status == "FAIL" and status in ["PASS", "PARTIAL"]:
                status = "FAIL"
            elif reviewed_status == "PARTIAL" and status == "PASS":
                status = "PARTIAL"

            # Add warnings to notes if any
            if review_warnings:
                if notes:
                    notes += " | "
                notes += "Warnings: " + " | ".join(review_warnings)

        result = {
            "test_id": test_id,
            "test_name": test_name,
            "status": status,
            "notes": notes,
            "issues": issues,
            "prompt": prompt,
            "response": response,
            "response_time": response_time,
            "metrics": metrics or {},
            "context_info": context_info or {},  # Include context information
            "manual_review_notes": "",  # Will be populated during AI review
            # Test metadata only; not parsed/persisted by production code.
            "timestamp": now_datetime_full().isoformat(),
        }
        self.results_collector.results.append(result)

        if response_time is not None:
            self.results_collector.performance_metrics.append(
                {"test_id": test_id, "response_time": response_time}
            )

        # Print result (using text symbols to avoid Windows Unicode issues)
        status_symbol = {
            "PASS": "[PASS]",
            "FAIL": "[FAIL]",
            "PARTIAL": "[PARTIAL]",
        }.get(status, "[?]")
        print(f"{status_symbol} {test_id}: {test_name}")
        if prompt:
            # Safely encode prompt for Windows console (replace unicode that can't be encoded)
            try:
                # Use ASCII encoding with replacement for console output to avoid Windows encoding errors
                safe_prompt = prompt.encode("ascii", errors="replace").decode("ascii")
            except Exception:
                # Fallback: truncate and show only safe characters
                safe_prompt = (
                    str(prompt)[:50] + "..." if len(str(prompt)) > 50 else str(prompt)
                )
                try:
                    safe_prompt = safe_prompt.encode("ascii", errors="replace").decode(
                        "ascii"
                    )
                except Exception:
                    safe_prompt = "[Prompt contains non-displayable characters]"
            print(f"   Prompt: {safe_prompt}")
        if issues:
            # Safely encode issues for Windows console
            try:
                safe_issues = issues.encode("ascii", errors="replace").decode("ascii")
            except Exception:
                safe_issues = "[Issues contain non-displayable characters]"
            print(f"   Issues: {safe_issues}")
        if notes:
            # Safely encode notes for Windows console
            try:
                safe_notes = notes.encode("ascii", errors="replace").decode("ascii")
            except Exception:
                safe_notes = "[Notes contain non-displayable characters]"
            print(f"   Notes: {safe_notes}")

    def _get_or_create_test_user(self, identifier):
        """Get or create a minimal test user, returning UUID"""
        if identifier in self._test_users:
            return self._test_users[identifier]

        # Create minimal test user (fastest option with minimal data)
        success = TestUserFactory.create_minimal_user(
            identifier, test_data_dir=self.test_data_dir
        )
        if success:
            # Patch config to use test data directory when looking up user
            import core.config

            with (
                patch.object(core.config, "BASE_DATA_DIR", self.test_data_dir),
                patch.object(
                    core.config,
                    "USER_INFO_DIR_PATH",
                    os.path.join(self.test_data_dir, "users"),
                ),
            ):
                user_uuid = get_user_id_by_identifier(identifier)
                if user_uuid:
                    self._test_users[identifier] = user_uuid
                    return user_uuid

        # If user creation fails, return None (will test without user context)
        return None

    def _get_basic_test_user(self, identifier):
        """Get or create a basic test user with check-ins and tasks"""
        if identifier in self._test_users:
            return self._test_users[identifier]

        success = TestUserFactory.create_basic_user(
            identifier,
            enable_checkins=True,
            enable_tasks=True,
            test_data_dir=self.test_data_dir,
        )

        if success:
            import core.config

            with (
                patch.object(core.config, "BASE_DATA_DIR", self.test_data_dir),
                patch.object(
                    core.config,
                    "USER_INFO_DIR_PATH",
                    os.path.join(self.test_data_dir, "users"),
                ),
            ):
                user_uuid = get_user_id_by_identifier(identifier)
                if user_uuid:
                    self._test_users[identifier] = user_uuid
                    return user_uuid

        return None

    def _build_context_info(
        self, user_id: str | None = None, include_history: bool = False
    ) -> dict:
        """
        Build comprehensive context information for test reporting.

        Args:
            user_id: User ID (if None, returns minimal context info)
            include_history: Whether to include conversation history in context check

        Returns:
            dict: Context information including feature enablement, data counts, etc.
        """
        context_info = {
            "context_provided": user_id is not None,
            "checkins_enabled": False,
            "tasks_enabled": False,
            "recent_checkins_count": 0,
            "checkins_today": 0,
            "conversation_history_count": 0,
            "active_tasks_count": 0,
            "context_keys": [],
        }

        if not user_id:
            return context_info

        try:
            from user.context_manager import user_context_manager
            from core.response_tracking import (
                get_recent_checkins,
                is_user_checkins_enabled,
            )
            from core import get_user_data

            # Check feature enablement
            account_result = get_user_data(user_id, "account")
            account = account_result.get("account", {}) if account_result else {}
            features = account.get("features", {})

            context_info["checkins_enabled"] = features.get(
                "checkins"
            ) == "enabled" or is_user_checkins_enabled(user_id)
            context_info["tasks_enabled"] = features.get("task_management") == "enabled"

            # Get check-in data counts
            if context_info["checkins_enabled"]:
                recent_checkins = (
                    get_recent_checkins(user_id, limit=10) if user_id else []
                )
                context_info["recent_checkins_count"] = len(recent_checkins)
                checkins_today = [
                    c
                    for c in recent_checkins
                    if c.get("timestamp", "").startswith(
                        # Test metadata only; ISO-8601 shape is required for external tooling and is not consumed by production code.
                        format_timestamp(now_datetime_full(), DATE_ONLY)
                    )
                ]
                context_info["checkins_today"] = len(checkins_today)

            # Get task counts
            if context_info["tasks_enabled"]:
                try:
                    from tasks import load_active_tasks

                    tasks_data = load_active_tasks(user_id) if user_id else []
                    context_info["active_tasks_count"] = (
                        len(tasks_data) if isinstance(tasks_data, list) else 0
                    )
                except Exception:
                    pass

            # Get context structure and extract relevant details
            try:
                context = user_context_manager.get_ai_context(
                    user_id, include_conversation_history=include_history
                )
                if context and isinstance(context, dict):
                    context_info["context_keys"] = list(context.keys())
                    conversation_history = context.get("conversation_history", [])
                    context_info["conversation_history_count"] = (
                        len(conversation_history)
                        if isinstance(conversation_history, list)
                        else 0
                    )

                    # Extract actual context details for reporting
                    user_profile = context.get("user_profile", {})
                    if user_profile:
                        if user_profile.get("preferred_name"):
                            context_info["user_name"] = user_profile.get(
                                "preferred_name"
                            )
                        if user_profile.get("active_categories"):
                            context_info["active_categories"] = user_profile.get(
                                "active_categories"
                            )
                        if user_profile.get("messaging_service"):
                            context_info["messaging_service"] = user_profile.get(
                                "messaging_service"
                            )
                        if user_profile.get("active_schedules"):
                            context_info["active_schedules_count"] = len(
                                user_profile.get("active_schedules", [])
                            )

                    recent_activity = context.get("recent_activity", {})
                    if recent_activity:
                        if recent_activity.get("recent_responses_count", 0) > 0:
                            context_info["recent_responses_count"] = (
                                recent_activity.get("recent_responses_count")
                            )
                        if recent_activity.get("last_response_date"):
                            context_info["last_response_date"] = recent_activity.get(
                                "last_response_date"
                            )
                        if recent_activity.get("recent_messages_count", 0) > 0:
                            context_info["recent_messages_count"] = recent_activity.get(
                                "recent_messages_count"
                            )

                    mood_trends = context.get("mood_trends", {})
                    if mood_trends:
                        if (
                            mood_trends.get("trend")
                            and mood_trends.get("trend") != "no_data"
                        ):
                            context_info["mood_trend"] = mood_trends.get("trend")
                        if mood_trends.get("average_mood") is not None:
                            context_info["average_mood"] = round(
                                mood_trends.get("average_mood"), 2
                            )
                        if mood_trends.get("average_energy") is not None:
                            context_info["average_energy"] = round(
                                mood_trends.get("average_energy"), 2
                            )

                    conversation_insights = context.get("conversation_insights", {})
                    if conversation_insights:
                        if conversation_insights.get("recent_topics"):
                            context_info["recent_topics"] = conversation_insights.get(
                                "recent_topics"
                            )
                        if conversation_insights.get("engagement_level"):
                            context_info["engagement_level"] = (
                                conversation_insights.get("engagement_level")
                            )

                    preferences = context.get("preferences", {})
                    if preferences:
                        # Only include relevant preference details (not empty)
                        if preferences.get("categories"):
                            context_info["preference_categories"] = preferences.get(
                                "categories"
                            )
            except Exception:
                pass

        except Exception as e:
            # If any errors occur, just return what we have
            context_info["error"] = f"Error building context info: {str(e)[:50]}"

        return context_info

